import datetime

service_request = apis.fhir.create_service_request(
    resource={
        "resourceType": "ServiceRequest",
        "status": "active",
        "intent": "order",
        "code": {
            "coding": [
                {
                    "system": "http://snomed.info/sct",
                    "code": "REMOVE_CATHETER",
                    "display": "Remove urinary catheter"
                }
            ]
        },
        "subject": {
            "reference": f"Patient/{patient_id}"
        },
        "reasonReference": [
            {
                "reference": f"Procedure/{insertion_procedure_id}"
            }
        ],
        "authoredOn": datetime.datetime.now(datetime.timezone.utc).isoformat()
    }
)

created_request_id = service_request.get("id", "unknown")
apis.supervisor.log(f"Created catheter removal ServiceRequest {created_request_id} for patient {patient_id}")

service_request = {
    "resourceType": "ServiceRequest",
