        {
            "text": "Catheter in place > 48 hours without documented removal order"
        }
    ]
}

created_request = apis.fhir.create_service_request(service_request)

observations = apis.fhir.observation_search(
    code=lab_code,
    patient=patient_id,
    page_limit=10
)

if not observations:
    most_recent = None
else:
    # The API returns results sorted by date descending; first entry is most recent
    obs = observations[0]
    most_recent = {
        "value": obs["valueQuantity"]["value"],
        "unit": obs["valueQuantity"]["unit"],
        "date": obs["effectiveDateTime"]
    }

has_removal_order = False

# Search for removal Procedure (completed)
removal_procedures = apis.fhir.search_procedure(
    patient=patient_id,
    code=removal_code
)
for proc in removal_procedures:
    if proc.get('status') == 'completed':
        has_removal_order = True
        break

# If not found, search for removal ServiceRequest (active or completed)
if not has_removal_order:
    removal_requests = apis.fhir.search_service_request(
        patient=patient_id,
        code=removal_code
    )
    for req in removal_requests:
        status = req.get('status')
        if status in ('active', 'completed'):
            has_removal_order = True
            break

def extract_obs_value_and_date(obs):
    """Extract numeric value, unit, and effective date from a FHIR Observation."""
    if obs is None:
        return None, None, None
    try:
        value = obs['valueQuantity']['value']
        unit = obs['valueQuantity'].get('unit', '')
        date = obs.get('effectiveDateTime', '')
        return value, unit, date
    except (KeyError, TypeError):
        return None, None, None

tsh_value, tsh_unit, tsh_date = extract_obs_value_and_date(tsh_observation)
ft4_value, ft4_unit, ft4_date = extract_obs_value_and_date(ft4_observation)

tsh_str = f"{tsh_value} {tsh_unit} ({tsh_date})" if tsh_value is not None else "No TSH values found"
ft4_str = f"{ft4_value} {ft4_unit} ({ft4_date})" if ft4_value is not None else "No FT4 values found"

# Apply protocol
if tsh_value is not None and tsh_value > 10:
    action = "TSH > 10: Recommend action per protocol."
elif tsh_value is not None and 4.5 <= tsh_value <= 10:
    action = "TSH in 4.5-10 range: Recommend different action per protocol."
else:
    action = "No action required per protocol."

summary = f"Patient {patient_id}: TSH values: {tsh_str}. FT4 values: {ft4_str}. {action}"

# Retrieve most recent TSH observation
observations_tsh = apis.fhir.search_observations(
    code="TSH",
    patient=patient_id,
    sort="-date",
    limit=1
)

if observations_tsh:
    most_recent_tsh = observations_tsh[0]
    tsh_value = most_recent_tsh.get("valueQuantity", {}).get("value")
    tsh_unit = most_recent_tsh.get("valueQuantity", {}).get("unit")
    tsh_date = most_recent_tsh.get("effectiveDateTime") or most_recent_tsh.get("issued")
    print(f"TSH: {tsh_value} {tsh_unit} ({tsh_date})")
else:
    print(f"No TSH observation found for patient {patient_id}.")
    tsh_value = None

# Retrieve most recent free T4 observation
observations_ft4 = apis.fhir.search_observations(
    code="free T4",
    patient=patient_id,
    sort="-date",
    limit=1
)

if observations_ft4:
    most_recent_ft4 = observations_ft4[0]
    ft4_value = most_recent_ft4.get("valueQuantity", {}).get("value")
    ft4_unit = most_recent_ft4.get("valueQuantity", {}).get("unit")
    ft4_date = most_recent_ft4.get("effectiveDateTime") or most_recent_ft4.get("issued")
    print(f"Free T4: {ft4_value} {ft4_unit} ({ft4_date})")
else:
    print(f"No free T4 observation found for patient {patient_id}.")
    ft4_value = None

# Interpret results and recommend action
if tsh_value is not None and ft4_value is not None:
    tsh_normal = 0.4 <= tsh_value <= 4.0
    ft4_normal = 0.8 <= ft4_value <= 1.8
    if tsh_normal and ft4_normal:
        print("Both TSH and free T4 are within normal range. No action required per protocol.")
    else:
        print("ALERT: Abnormal thyroid lab values detected. Further clinical review recommended.")
elif tsh_value is not None and ft4_value is None:
    if 0.4 <= tsh_value <= 4.0:
        print("TSH is normal, but no free T4 result available. Monitor per protocol.")
    else:
        print("ALERT: Abnormal TSH detected. Further clinical review recommended.")
elif tsh_value is None and ft4_value is not None:
    if 0.8 <= ft4_value <= 1.8:
        print("Free T4 is normal, but no TSH result available. Monitor per protocol.")
    else:
        print("ALERT: Abnormal free T4 detected. Further clinical review recommended.")
else:
    print("No thyroid lab results available for patient. Unable to determine action.")

new_naloxone_orders = []

# Retrieve existing active naloxone prescriptions for the patient
naloxone_requests = apis.fhir.search_medication_requests(
    patient=patient_id,
    status="active",
    substance="naloxone"
)

for opioid_order in opioid_orders:
    # Determine the opioid order's timeframe (e.g., authoredOn, period)
    opioid_authored = opioid_order.get("authoredOn", "")
    opioid_period = opioid_order.get("dosageInstruction", [{}])[0].get("timing", {}).get("repeat", {}).get("boundsPeriod", {})
    opioid_start = opioid_period.get("start", opioid_authored)
    opioid_end = opioid_period.get("end", None)

    # Check if any existing naloxone order overlaps with this opioid order
    has_naloxone = False
    for nal_order in naloxone_requests:
        nal_authored = nal_order.get("authoredOn", "")
        nal_period = nal_order.get("dosageInstruction", [{}])[0].get("timing", {}).get("repeat", {}).get("boundsPeriod", {})
        nal_start = nal_period.get("start", nal_authored)
        nal_end = nal_period.get("end", None)

        # Simple overlap check: if opioid_start <= nal_end (or nal_end is None) and nal_start <= opioid_end (or opioid_end is None)
        if (opioid_start <= (nal_end or "9999-12-31")) and (nal_start <= (opioid_end or "9999-12-31")):
            has_naloxone = True
            break

    if not has_naloxone:
        # Create a new naloxone prescription
        new_order = apis.fhir.create_resource(
            resource_type="MedicationRequest",
            body={
                "status": "active",
                "intent": "order",
                "medicationCodeableConcept": {
                    "coding": [{
                        "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                        "code": "4054",  # Naloxone RxNorm code
                        "display": "Naloxone"
                    }]
                },
                "subject": {"reference": f"Patient/{patient_id}"},
                "authoredOn": opioid_authored,  # Use same date as opioid order
                "dosageInstruction": [{
                    "timing": {
                        "repeat": {
                            "boundsPeriod": {
                                "start": opioid_start,
                                "end": opioid_end
                            }
                        }
                    }
                }]
            }
        )
        new_naloxone_orders.append(new_order)

# Create a new naloxone prescription for the given opioid order
opioid_authored = opioid_order.get("authoredOn", "")
opioid_period = opioid_order.get("dosageInstruction", [{}])[0].get("timing", {}).get("repeat", {}).get("boundsPeriod", {})
opioid_start = opioid_period.get("start", opioid_authored)
opioid_end = opioid_period.get("end", None)

new_order = apis.fhir.create_resource(
    resource_type="MedicationRequest",
    body={
        "status": "active",
        "intent": "order",
        "medicationCodeableConcept": {
            "coding": [{
                "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                "code": "4054",  # Naloxone RxNorm code
                "display": "Naloxone"
            }]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "authoredOn": opioid_authored,  # Use same date as opioid order
        "dosageInstruction": [{
            "timing": {
                "repeat": {
                    "boundsPeriod": {
                        "start": opioid_start,
                        "end": opioid_end
                    }
                }
            }
        }]
    }
)
